import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getFeeRevenueCorrelation(chainName, tokenAddress, feeRecipient) {
  const [prices, txns] = await Promise.all([
    client.PricingService.getTokenPrices(chainName, "USD", tokenAddress),
    client.TransactionService.getTransactionsForAddressV3(chainName, feeRecipient),
  ]);
  const feeIncome = (txns.data?.items ?? []).reduce((s, t) => s + (t.value_quote ?? 0), 0);
  const currentPrice = prices.data?.items?.[0]?.price ?? 0;
  return { tokenAddress, feeIncome, currentPrice, revenuePerDollar: feeIncome / Math.max(1, currentPrice) };
}
